import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { FileText, ClipboardList, Plus, ChevronDown, ChevronRight, PackageOpen, CheckCircle2, Layers, Wrench, FileDown, Send, Printer } from 'lucide-react';
import api, { getDashboard, getConfig } from '../../services/api';
import Loading from '../common/Loading';
import { formatCurrency, formatDate, badgeClass } from '../../utils/formatters';

const groups = [
  {
    key: 'presupuestos',
    label: 'PRESUPUESTOS',
    icon: FileText,
    color: '#f59e0b',
    items: [
      { label: 'Presupuestos Pendientes', dataKey: 'presupuestos_pendientes', path: '/presupuestos', icon: FileText, color: '#f59e0b', bg: '#fef3c7' },
      { label: 'Próximas Entregas', dataKey: 'trabajos_proxima_entrega', path: '/presupuestos', icon: FileText, color: '#f97316', bg: '#fff7ed' },
    ],
  },
  {
    key: 'ordenes',
    label: 'ÓRDENES DE TRABAJO',
    icon: ClipboardList,
    color: '#3b82f6',
    items: [
      { label: 'EN MEDICIÓN', dataKey: 'ordenes_en_medicion', path: '/ordenes?estado=EN MEDICIÓN', icon: Wrench, color: '#8b5cf6', bg: '#ede9fe' },
      { label: 'EN TALLER', dataKey: 'ordenes_en_taller', path: '/ordenes?estado=EN EL TALLER', icon: CheckCircle2, color: '#22c55e', bg: '#dcfce7' },
      { label: 'ENTREGADO', dataKey: 'ordenes_entregadas_count', path: '/ordenes?estado=ENTREGADO', icon: Layers, color: '#6b7280', bg: '#f3f4f6' },
    ],
  },
  {
    key: 'piletas',
    label: 'PILETAS',
    icon: PackageOpen,
    color: '#06b6d4',
    items: [
      { label: 'Stock', dataKey: 'piletas_en_stock', path: '/stock-piletas', icon: PackageOpen, color: '#06b6d4', bg: '#cffafe' },
    ],
  },
];

export default function Dashboard() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [logoUrl, setLogoUrl] = useState('');
  const [expanded, setExpanded] = useState({});
  const [showPresupuestoDropdown, setShowPresupuestoDropdown] = useState(false);
  const presupuestoDropdownRef = useRef(null);
  const navigate = useNavigate();

  useEffect(() => {
    getDashboard()
      .then((res) => setData(res.data))
      .finally(() => setLoading(false));
    getConfig().then((res) => {
      const logo = res.data.find((c) => c.key === 'logo');
      if (logo?.value) {
        const base = (api.defaults.baseURL || 'http://localhost:8000/api').replace('/api', '');
        setLogoUrl(`${base}/${logo.value}`);
      }
    });
  }, []);

  useEffect(() => {
    const handleClick = (e) => {
      if (presupuestoDropdownRef.current && !presupuestoDropdownRef.current.contains(e.target)) {
        setShowPresupuestoDropdown(false);
      }
    };
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, []);

  if (loading) return <Loading />;

  const toggle = (key) => setExpanded((prev) => ({ ...prev, [key]: !prev[key] }));

  const totalEntregadas = (data?.ordenes_entregadas?.length || 0);

  return (
    <div style={{ position: 'relative' }}>
      {logoUrl && (
        <div style={{
          position: 'fixed', top: '50%', left: '50%', transform: 'translate(-50%, -50%)',
          width: 400, height: 400, opacity: 0.06, pointerEvents: 'none', zIndex: 0,
          backgroundImage: `url(${logoUrl})`, backgroundSize: 'contain', backgroundPosition: 'center', backgroundRepeat: 'no-repeat',
        }} />
      )}
      <div style={{ position: 'relative', zIndex: 1 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
        <h1 style={{ fontSize: 24, fontWeight: 700 }}>MENÚ</h1>
        <div style={{ display: 'flex', gap: 10 }}>
          <div ref={presupuestoDropdownRef} style={{ position: 'relative' }}>
            <button className="btn btn-primary" onClick={() => setShowPresupuestoDropdown(!showPresupuestoDropdown)} style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
              <Plus size={16} /> PRESUPUESTO <ChevronDown size={14} />
            </button>
            {showPresupuestoDropdown && (
              <div style={{
                position: 'absolute', top: '100%', left: 0, marginTop: 4,
                background: '#fff', border: '1px solid #e2e8f0', borderRadius: 8,
                boxShadow: '0 4px 12px rgba(0,0,0,0.1)', zIndex: 100, minWidth: 220, overflow: 'hidden'
              }}>
                <div style={{ padding: '8px 16px', cursor: 'pointer', fontSize: 14, fontWeight: 600, borderBottom: '1px solid #f1f5f9' }}
                  onClick={() => { navigate('/presupuestos/nuevo'); setShowPresupuestoDropdown(false); }}>
                  <Plus size={14} style={{ marginRight: 8 }} /> NUEVO PRESUPUESTO
                </div>
                <div style={{ padding: '8px 16px', cursor: 'pointer', fontSize: 14, fontWeight: 600 }}
                  onClick={() => { navigate('/presupuestos'); setShowPresupuestoDropdown(false); }}>
                  <FileText size={14} style={{ marginRight: 8 }} /> PRESUPUESTOS REALIZADOS
                </div>
              </div>
            )}
          </div>
          <button className="btn btn-success" onClick={() => navigate('/ordenes/nuevo')}>
            <Plus size={16} /> Nueva Orden
          </button>
          <button className="btn btn-outline" onClick={() => navigate('/clientes/nuevo')}>
            <Plus size={16} /> Nuevo Cliente
          </button>
        </div>
      </div>

      <h2 className="section-title" style={{ marginBottom: 16 }}>MÉTRICAS</h2>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: 12, marginBottom: 24 }}>
        {[
          { label: 'Total Órdenes Activas', value: data?.total_ordenes_activas },
          { label: 'Total Presupuestos', value: data?.total_presupuestos },
          { label: 'Total Órdenes', value: data?.total_ordenes },
          { label: 'Total Ingresos', value: formatCurrency(data?.total_ingresos) },
          { label: 'Pendiente de Cobro', value: formatCurrency(data?.total_pendiente_cobro) },
          { label: 'Entregadas este mes', value: data?.ordenes_entregadas_mes },
          { label: 'Aprobados este mes', value: data?.presupuestos_aprobados_mes },
        ].map((m) => (
          <div key={m.label} style={{ background: '#fff', padding: '16px', borderRadius: 12, border: '1px solid #e2e8f0' }}>
            <div style={{ fontSize: 12, color: '#64748b', marginBottom: 4 }}>{m.label}</div>
            <div style={{ fontSize: 24, fontWeight: 700 }}>{m.value}</div>
          </div>
        ))}
      </div>

      <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
        {groups.map((group) => (
          <div key={group.key} className="card" style={{ padding: 0, overflow: 'hidden' }}>
            <div
              onClick={() => toggle(group.key)}
              style={{
                display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                padding: '16px 20px', cursor: 'pointer', userSelect: 'none',
                background: expanded[group.key] ? '#f8fafc' : '#fff',
                borderBottom: expanded[group.key] ? '1px solid #e5e7eb' : 'none',
              }}
            >
              <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                <div style={{ padding: 8, borderRadius: 10, background: `${group.color}15` }}>
                  <group.icon size={20} color={group.color} />
                </div>
                <span style={{ fontWeight: 700, fontSize: 15 }}>{group.label}</span>
              </div>
              {expanded[group.key] ? <ChevronDown size={18} color="#64748b" /> : <ChevronRight size={18} color="#64748b" />}
            </div>
            {expanded[group.key] && (
              <div style={{ padding: '12px 20px 16px', display: 'flex', flexDirection: 'column', gap: 8 }}>
                {group.items.map((item) => {
                  const value = item.dataKey === 'ordenes_entregadas_count' ? totalEntregadas : (data?.[item.dataKey] || 0);
                  return (
                    <div
                      key={item.label}
                      className="stat-card"
                      onClick={() => navigate(item.path)}
                      style={{ cursor: 'pointer', margin: 0, display: 'flex', alignItems: 'center', gap: 12, padding: '12px 16px' }}
                    >
                      <div className="icon" style={{ background: item.bg, width: 40, height: 40 }}>
                        <item.icon size={18} color={item.color} />
                      </div>
                      <div style={{ flex: 1 }}>
                        <div className="label" style={{ textAlign: 'left' }}>{item.label}</div>
                      </div>
                      <div className="value" style={{ color: item.color, fontSize: 20 }}>{value}</div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        ))}
      </div>

      <div style={{ marginTop: 32 }}>
        <h2 className="section-title" style={{ marginBottom: 16 }}>ACCIONES</h2>
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
          <button
            className="btn btn-primary"
            onClick={() => navigate('/presupuestos')}
            style={{ flex: 1, minWidth: 180, justifyContent: 'center', padding: '14px 20px', fontSize: 15, fontWeight: 600 }}
          >
            <FileDown size={20} /> GENERAR PDF
          </button>
          <button
            className="btn btn-success"
            onClick={() => navigate('/presupuestos')}
            style={{ flex: 1, minWidth: 180, justifyContent: 'center', padding: '14px 20px', fontSize: 15, fontWeight: 600 }}
          >
            <Send size={20} /> ENVIAR POR WHATS APP
          </button>
          <button
            className="btn btn-outline"
            onClick={() => window.print()}
            style={{ flex: 1, minWidth: 180, justifyContent: 'center', padding: '14px 20px', fontSize: 15, fontWeight: 600 }}
          >
            <Printer size={20} /> IMPRIMIR
          </button>
        </div>
      </div>

      {data?.ordenes_entregadas?.length > 0 && (
        <div style={{ marginTop: 32 }}>
          <h2 className="section-title" style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <CheckCircle2 size={20} /> ÓRDENES ENTREGADAS
          </h2>
          <p style={{ color: '#6b7280', fontSize: 14, marginBottom: 12 }}>
            Órdenes entregadas con más de 2 meses de antigüedad
          </p>
          <div className="table-container">
            <table className="table">
              <thead>
                <tr>
                  <th>N°</th>
                  <th>Cliente</th>
                  <th>Total</th>
                  <th>Estado</th>
                  <th>Entregada</th>
                </tr>
              </thead>
              <tbody>
                {data.ordenes_entregadas.map((o) => (
                  <tr key={o.id} style={{ cursor: 'pointer', opacity: 0.7 }}
                    onClick={() => navigate(`/ordenes/${o.id}`)}
                  >
                    <td><strong>{o.numero}</strong></td>
                    <td>{o.cliente_nombre || '-'}</td>
                    <td>{formatCurrency(o.total)}</td>
                    <td><span className={badgeClass(o.estado)}>{o.estado}</span></td>
                    <td>{o.updated_at ? formatDate(o.updated_at) : '-'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
      </div>
    </div>
  );
}
